    42	/**
    43	 * Generates a plain text representation of the extracted PDF contents.
    44	 */
    45	public class TextGenerator implements Closeable {
    46	
    47	    private static final Logger LOGGER = Logger.getLogger(TextGenerator.class.getCanonicalName());
    48	    private static final String INDENT = "  ";
    49	
    50	    private final java.io.Writer textWriter;
    51	    private final String textFileName;
    52	    private final String lineSeparator = System.lineSeparator();
    53	    private final String textPageSeparator;
    54	    private final boolean includeHeaderFooter;
    55	
    56	    public TextGenerator(File inputPdf, Config config) throws IOException {
    57	        String cutPdfFileName = inputPdf.getName();
    58	        this.textFileName = config.getOutputFolder() + File.separator + cutPdfFileName.substring(0, cutPdfFileName.length() - 3) + "txt";
    59	        this.textWriter = new FileWriter(textFileName, StandardCharsets.UTF_8);
    60	        this.textPageSeparator = config.getTextPageSeparator();
    61	        this.includeHeaderFooter = config.isIncludeHeaderFooter();
    62	    }
    63	
    64	    /**
    65	     * Creates a TextGenerator that writes to an arbitrary Writer (e.g., stdout).
    66	     */
    67	    public TextGenerator(java.io.Writer writer, Config config) {
    68	        this.textFileName = null;
    69	        this.textWriter = writer;
    70	        this.textPageSeparator = config.getTextPageSeparator();
    71	        this.includeHeaderFooter = config.isIncludeHeaderFooter();
    72	    }
    73	
    74	    public void writeToText(List<List<IObject>> contents) {
    75	        try {
    76	            for (int pageIndex = 0; pageIndex < contents.size(); pageIndex++) {
    77	                writePageSeparator(pageIndex);
    78	                List<IObject> pageContents = contents.get(pageIndex);
    79	                writeContents(pageContents, 0);
    80	                if (pageIndex < contents.size() - 1) {
    81	                    textWriter.write(lineSeparator);
    82	                }
    83	            }
    84	            LOGGER.log(Level.INFO, "Created {0}", textFileName);
    85	        } catch (Exception e) {
    86	            LOGGER.log(Level.WARNING, "Unable to create text output: " + e.getMessage());
    87	        }
    88	    }
    89	
    90	    private void writePageSeparator(int pageIndex) throws IOException {
    91	        if (!textPageSeparator.isEmpty()) {
    92	            textWriter.write(textPageSeparator.contains(Config.PAGE_NUMBER_STRING)
    93	                ? textPageSeparator.replace(Config.PAGE_NUMBER_STRING, String.valueOf(pageIndex + 1))
    94	                : textPageSeparator);
    95	            textWriter.write(lineSeparator);
    96	        }
    97	    }
    98	
    99	    private void writeContents(List<IObject> contents, int indentLevel) throws IOException {
   100	        for (int index = 0; index < contents.size(); index++) {
   101	            write(contents.get(index), indentLevel);
   102	            if (index < contents.size() - 1) {
   103	                textWriter.write(lineSeparator);
   104	            }
   105	        }
   106	    }
   107	
   108	    private void write(IObject object, int indentLevel) throws IOException {
   109	        if (object instanceof SemanticHeaderOrFooter) {
   110	            if (includeHeaderFooter) {
   111	                writeHeaderOrFooter((SemanticHeaderOrFooter) object, indentLevel);
   112	            }
   113	        } else if (object instanceof SemanticHeading) {
   114	            writeMultiline(((SemanticHeading) object).getValue(), indentLevel);
   115	        } else if (object instanceof SemanticParagraph) {
   116	            writeMultiline(((SemanticParagraph) object).getValue(), indentLevel);
   117	        } else if (object instanceof SemanticTextNode) {
   118	            writeMultiline(((SemanticTextNode) object).getValue(), indentLevel);
   119	        } else if (object instanceof PDFList) {
   120	            writeList((PDFList) object, indentLevel);
   121	        } else if (object instanceof TableBorder) {
   122	            writeTable((TableBorder) object, indentLevel);
   123	        }
   124	    }
   125	
   126	    private void writeHeaderOrFooter(SemanticHeaderOrFooter headerOrFooter, int indentLevel) throws IOException {
   127	        writeContents(headerOrFooter.getContents(), indentLevel);
   128	    }
   129	
   130	    private void writeList(PDFList list, int indentLevel) throws IOException {
   131	        for (ListItem item : list.getListItems()) {
   132	            String indent = indent(indentLevel);
   133	            String itemText = compactWhitespace(collectPlainText(item.getContents()));
   134	            if (!itemText.isEmpty()) {
   135	                textWriter.write(indent);
   136	                textWriter.write(itemText);
   137	                textWriter.write(lineSeparator);
   138	            }
   139	            if (!item.getContents().isEmpty()) {
   140	                writeContents(item.getContents(), indentLevel + 1);
   141	            }
   142	        }
   143	    }
   144	
   145	    private void writeTable(TableBorder table, int indentLevel) throws IOException {
   146	        String indent = indent(indentLevel);
   147	        for (TableBorderRow row : table.getRows()) {
   148	            String rowText = Arrays.stream(row.getCells())
   149	                .map(cell -> compactWhitespace(collectPlainText(cell.getContents())))
   150	                .filter(text -> !text.isEmpty())
   151	                .collect(Collectors.joining("\t"));
   152	            if (rowText.isEmpty()) {
   153	                continue;
   154	            }
   155	            textWriter.write(indent);
   156	            textWriter.write(rowText);
   157	            textWriter.write(lineSeparator);
   158	        }
   159	    }
   160	
   161	    private String collectPlainText(List<IObject> contents) {
   162	        StringBuilder builder = new StringBuilder();
   163	        for (IObject content : contents) {
   164	            String piece = extractPlainText(content);
   165	            if (piece.isEmpty()) {
   166	                continue;
   167	            }
   168	            if (builder.length() > 0) {
   169	                builder.append(' ');
   170	            }
   171	            builder.append(piece);
   172	        }
   173	        return builder.toString();
   174	    }
   175	
   176	    private String extractPlainText(IObject content) {
   177	        if (content instanceof SemanticHeaderOrFooter) {
   178	            if (includeHeaderFooter) {
   179	                return collectPlainText(((SemanticHeaderOrFooter) content).getContents());
   180	            }
   181	            return "";
   182	        } else if (content instanceof SemanticHeading) {
   183	            return sanitize(((SemanticHeading) content).getValue());
   184	        } else if (content instanceof SemanticParagraph) {
   185	            return sanitize(((SemanticParagraph) content).getValue());
   186	        } else if (content instanceof SemanticTextNode) {
   187	            return sanitize(((SemanticTextNode) content).getValue());
   188	        } else if (content instanceof PDFList) {
   189	            PDFList list = (PDFList) content;
   190	            return list.getListItems().stream()
   191	                .map(item -> compactWhitespace(collectPlainText(item.getContents())))
   192	                .filter(text -> !text.isEmpty())
   193	                .collect(Collectors.joining(" "));
   194	        } else if (content instanceof TableBorder) {
   195	            TableBorder table = (TableBorder) content;
   196	            return Arrays.stream(table.getRows())
   197	                .map(row -> Arrays.stream(row.getCells())
   198	                    .map(cell -> compactWhitespace(collectPlainText(cell.getContents())))
   199	                    .filter(text -> !text.isEmpty())
   200	                    .collect(Collectors.joining(" ")))
   201	                .filter(text -> !text.isEmpty())
   202	                .collect(Collectors.joining(" "));
   203	        }
   204	        return "";
   205	    }
   206	
   207	    private void writeMultiline(String value, int indentLevel) throws IOException {
   208	        if (value == null) {
   209	            return;
   210	        }
   211	        String sanitized = sanitize(value);
   212	        String indent = indent(indentLevel);
   213	        String[] lines = sanitized.split("\r?\n", -1);
   214	        for (String line : lines) {
   215	            if (line.isBlank()) {
   216	                continue;
   217	            }
   218	            textWriter.write(indent);
   219	            textWriter.write(line);
   220	            textWriter.write(lineSeparator);
   221	        }
   222	    }
   223	
   224	    private String indent(int level) {
   225	        if (level <= 0) {
   226	            return "";
   227	        }
   228	        return INDENT.repeat(level);
   229	    }
   230	
   231	    private String sanitize(String value) {
   232	        return value == null ? "" : value.replace("\u0000", " ");
   233	    }
   234	
   235	    private String compactWhitespace(String value) {
   236	        if (value == null) {
   237	            return "";
   238	        }
   239	        String sanitized = sanitize(value);
   240	        return sanitized.replaceAll("\\s+", " ").trim();
   241	    }
   242	
   243	    @Override
   244	    public void close() throws IOException {
   245	        if (textWriter != null) {
   246	            textWriter.close();
   247	        }
   248	    }
   249	}
