   264	    protected void writeTable(TableBorder table) throws IOException {
   265	        enterTable();
   266	        for (int rowNumber = 0; rowNumber < table.getNumberOfRows(); rowNumber++) {
   267	            TableBorderRow row = table.getRow(rowNumber);
   268	            markdownWriter.write(MarkdownSyntax.TABLE_COLUMN_SEPARATOR);
   269	            for (int colNumber = 0; colNumber < table.getNumberOfColumns(); colNumber++) {
   270	                TableBorderCell cell = row.getCell(colNumber);
   271	                if (cell.getRowNumber() == rowNumber && cell.getColNumber() == colNumber) {
   272	                    List<IObject> cellContents = cell.getContents();
   273	                    writeContents(cellContents, true);
   274	                } else {
   275	                    writeSpace();
   276	                }
   277	                markdownWriter.write(MarkdownSyntax.TABLE_COLUMN_SEPARATOR);
   278	            }
   279	            markdownWriter.write(MarkdownSyntax.LINE_BREAK);
   280	            //Due to markdown syntax we have to separate column headers
   281	            if (rowNumber == 0) {
   282	                markdownWriter.write(MarkdownSyntax.TABLE_COLUMN_SEPARATOR);
