    39	    public static List<IObject> processTextLines(List<IObject> contents) {
    40	        List<IObject> newContents = new ArrayList<>();
    41	        TextLine previousLine = new TextLine(new TextChunk(""));
    42	        boolean isSeparateLine = false;
    43	        for (IObject content : contents) {
    44	            if (content instanceof TextChunk) {
    45	                TextChunk textChunk = (TextChunk) content;
    46	                if (textChunk.isWhiteSpaceChunk() || textChunk.isEmpty()) {
    47	                    continue;
    48	                }
    49	                TextLine currentLine = new TextLine(textChunk);
    50	                double oneLineProbability = ChunksMergeUtils.countOneLineProbability(new SemanticTextNode(), previousLine, currentLine);
    51	                isSeparateLine |= (oneLineProbability < ONE_LINE_PROBABILITY) || previousLine.isHiddenText() != currentLine.isHiddenText();
    52	                if (isSeparateLine) {
    53	                    previousLine.setBoundingBox(new BoundingBox(previousLine.getBoundingBox()));
    54	                    previousLine = currentLine;
    55	                    newContents.add(previousLine);
    56	                } else {
    57	                    previousLine.add(currentLine);
    58	                }
    59	                isSeparateLine = false;
    60	            } else {
    61	                if (content instanceof TableBorder) {
    62	                    isSeparateLine = true;
    63	                }
    64	                newContents.add(content);
    65	            }
    66	        }
    67	        for (int i = 0; i < newContents.size(); i++) {
    68	            IObject content = newContents.get(i);
    69	            if (content instanceof TextLine) {
    70	                TextLine textLine = (TextLine) content;
    71	                textLine.getTextChunks().sort(TEXT_CHUNK_COMPARATOR);
    72	                double threshold = textLine.getFontSize() * TextChunkUtils.TEXT_LINE_SPACE_RATIO;
    73	                newContents.set(i, getTextLineWithSpaces(textLine, threshold));
    74	            }
    75	        }
    76	        linkTextLinesWithConnectedLineArtBullet(newContents);
    77	        return newContents;
    78	    }
