    80	    private static TextLine getTextLineWithSpaces(TextLine textLine, double threshold) {
    81	        List<TextChunk> textChunks = textLine.getTextChunks();
    82	        TextChunk currentTextChunk = textChunks.get(0);
    83	        double previousEnd = currentTextChunk.getBoundingBox().getRightX();
    84	        TextLine newLine = new TextLine();
    85	        newLine.add(currentTextChunk);
    86	        for (int i = 1; i < textChunks.size(); i++) {
    87	            currentTextChunk = textChunks.get(i);
    88	            double currentStart = currentTextChunk.getBoundingBox().getLeftX();
    89	            if (currentStart - previousEnd > threshold) {
    90	                BoundingBox spaceBBox = new BoundingBox(currentTextChunk.getBoundingBox());
    91	                spaceBBox.setLeftX(previousEnd);
    92	                spaceBBox.setRightX(currentStart);
    93	                TextChunk spaceChunk = new TextChunk(spaceBBox, " ", textLine.getFontSize(), textLine.getBaseLine());
    94	                newLine.add(spaceChunk);
    95	            }
    96	            previousEnd = currentTextChunk.getBoundingBox().getRightX();
    97	            newLine.add(currentTextChunk);
    98	        }
    99	
   100	        return newLine;
   101	    }
