   337	    public static void sortContents(List<List<IObject>> contents, Config config) {
   338	        String readingOrder = config.getReadingOrder();
   339	
   340	        // xycut: XY-Cut++ sorting (per-page, stateless — safe to parallelize)
   341	        if (Config.READING_ORDER_XYCUT.equals(readingOrder)) {
   342	            IntStream.range(0, StaticContainers.getDocument().getNumberOfPages()).parallel().forEach(pageNumber ->
   343	                contents.set(pageNumber, XYCutPlusPlusSorter.sort(contents.get(pageNumber)))
   344	            );
   345	            return;
   346	        }
   347	
   348	        // Log warning for unknown reading order values
   349	        if (!Config.READING_ORDER_OFF.equals(readingOrder)) {
   350	            LOGGER.log(Level.WARNING, "Unknown reading order value ''{0}'', using default ''off''", readingOrder);
   351	        }
   352	
   353	        // off: skip sorting (keep PDF COS object order)
   354	    }
