    39	public class ContentFilterProcessor {
    40	
    41	    private static final Logger LOGGER = Logger.getLogger(ContentFilterProcessor.class.getCanonicalName());
    42	
    43	    /**
    44	     * Filters and cleans page contents based on configuration.
    45	     *
    46	     * @param inputPdfName the path to the PDF file
    47	     * @param contents the raw page contents
    48	     * @param pageNumber the page number (0-indexed)
    49	     * @param config the configuration settings
    50	     * @return the filtered list of content objects
    51	     * @throws IOException if unable to process the content
    52	     */
    53	    public static List<IObject> getFilteredContents(String inputPdfName, List<IChunk> contents, int pageNumber,
    54	                                                    Config config) throws IOException {
    55	        List<IObject> pageContents = new ArrayList<>(contents);
    56	        TextProcessor.removeSameTextChunks(pageContents);
    57	        pageContents = DocumentProcessor.removeNullObjectsFromList(pageContents);
    58	        TextProcessor.removeTextDecorationImages(pageContents);
    59	        pageContents = DocumentProcessor.removeNullObjectsFromList(pageContents);
    60	        if (config.getFilterConfig().isFilterTinyText()) {
    61	            TextProcessor.filterTinyText(pageContents);
    62	            pageContents = DocumentProcessor.removeNullObjectsFromList(pageContents);
    63	        }
    64	        if (config.getFilterConfig().isFilterOutOfPage()) {
    65	            filterOutOfPageContents(pageNumber, pageContents);
    66	            pageContents = DocumentProcessor.removeNullObjectsFromList(pageContents);
    67	        }
    68	        TextProcessor.mergeCloseTextChunks(pageContents);
    69	        pageContents = DocumentProcessor.removeNullObjectsFromList(pageContents);
    70	        TextProcessor.trimTextChunksWhiteSpaces(pageContents);
    71	        filterConsecutiveSpaces(pageContents);
    72	        pageContents = splitTextChunksByWhiteSpacesInPageContents(pageContents);
    73	        // HiddenText detection moved to DocumentProcessor (sequential post-processing)
    74	        // to avoid ContrastRatioConsumer per-thread PDF rendering overhead
    75	        double replacementCharRatio = TextProcessor.measureReplacementCharRatio(pageContents);
    76	        StaticLayoutContainers.setReplacementCharRatio(pageNumber, replacementCharRatio);
    77	        if (replacementCharRatio >= 0.3) {
    78	            LOGGER.log(Level.WARNING,
    79	                "Page {0}: {1,number,#.#%} of characters are replacement characters (U+FFFD). "
    80	                + "This PDF likely contains CID-keyed fonts without ToUnicode mappings. "
    81	                + "Text extraction may be incomplete. Consider using --hybrid-mode for OCR fallback.",
    82	                new Object[]{pageNumber + 1, replacementCharRatio});
    83	        }
    84	        TextProcessor.replaceUndefinedCharacters(pageContents, config.getReplaceInvalidChars());
    85	        processBackgrounds(pageNumber, pageContents);
    86	        return pageContents;
    87	    }
