    89	    /**
    90	     * Detects and removes background elements from page contents.
    91	     *
    92	     * @param pageNumber the page number (0-indexed)
    93	     * @param contents the page contents to process
    94	     */
    95	    public static void processBackgrounds(int pageNumber, List<IObject> contents) {
    96	        BoundingBox pageBoundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
    97	        if (pageBoundingBox == null) {
    98	            return;
    99	        }
   100	        Set<LineArtChunk> backgrounds = new HashSet<>();
   101	        for (IObject content : contents) {
   102	            if (content instanceof LineArtChunk) {
   103	                if (isBackground(content, pageBoundingBox)) {
   104	                    backgrounds.add((LineArtChunk) content);
   105	                }
   106	            }
   107	        }
   108	        if (!backgrounds.isEmpty()) {
   109	            LOGGER.log(Level.WARNING, "Detected background on page " + pageNumber);
   110	            contents.removeAll(backgrounds);
   111	        }
   112	    }
