   114	    private static void filterConsecutiveSpaces(List<IObject> pageContents) {
   115	        for (IObject object : pageContents) {
   116	            if (object instanceof TextChunk) {
   117	                ((TextChunk) object).compressSpaces();
   118	            }
   119	        }
   120	    }
   121	
   122	    private static boolean isBackground(IObject content, BoundingBox pageBoundingBox) {
   123	        return (content.getBoundingBox().getWidth() > 0.5 * pageBoundingBox.getWidth() &&
   124	            content.getBoundingBox().getHeight() > 0.1 * pageBoundingBox.getHeight()) ||
   125	            (content.getBoundingBox().getWidth() > 0.1 * pageBoundingBox.getWidth() &&
   126	                content.getBoundingBox().getHeight() > 0.5 * pageBoundingBox.getHeight());
   127	    }
   128	
   129	    private static void filterOutOfPageContents(int pageNumber, List<IObject> contents) {
   130	        BoundingBox pageBoundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
   131	        if (pageBoundingBox == null) {
   132	            return;
   133	        }
   134	        pageBoundingBox.move(-pageBoundingBox.getLeftX(), -pageBoundingBox.getBottomY());
   135	        for (int index = 0; index < contents.size(); index++) {
   136	            IObject object = contents.get(index);
   137	            if (object != null && pageBoundingBox.notOverlaps(object.getBoundingBox())) {
   138	                contents.set(index, null);
   139	            }
   140	        }
   141	    }
   142	
   143	    private static List<IObject> splitTextChunksByWhiteSpacesInPageContents(List<IObject> contents) {
   144	        List<IObject> newContents = new ArrayList<>();
   145	        for (IObject object : contents) {
   146	            if (object instanceof TextChunk) {
   147	                TextChunk textChunk = (TextChunk) object;
   148	                List<TextChunk> splitChunks = TextChunkUtils.splitTextChunkByWhiteSpaces(textChunk);
   149	                newContents.addAll(splitChunks);
   150	            } else {
   151	                newContents.add(object);
   152	            }
   153	        }
   154	        return newContents;
   155	    }
