import org.verapdf.wcag.algorithms.semanticalgorithms.containers.StaticContainers;
import org.opendataloader.pdf.processors.TextLineProcessor;

import java.util.ArrayList;
import java.util.List;

/**
 * Reproduction test for word concatenation issue.
 * Tests that spaces are correctly inserted between text chunks
 * with a gap that is below the TEXT_LINE_SPACE_RATIO threshold (0.17 * fontSize).
 */
public class ReproTest {
    public static void main(String[] args) {
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticContainers.setIsDataLoader(true);

        // Test 1: Chunks with a small gap (below fontSize * 0.17 threshold)
        // For fontSize=10, threshold=1.7. Gap of 1.5 should still get a space.
        testSmallGap();

        // Test 2: Chunks representing typical words simlar to "Evolution Of Search"
        testWordGaps();

        // Test 3: Existing behavior - overlapping chunks
        testOverlappingChunks();

        // Test 4: Existing behavior - large gap
        testLargeGap();

        System.out.println("All tests passed!");
    }

    static void testSmallGap() {
        List<IObject> contents = new ArrayList<>();
        // fontSize=10, threshold=1.7. Gap=1.5 is below threshold.
        TextChunk chunk1 = new TextChunk(new BoundingBox(0, 10.0, 100.0, 30.0, 110.0),
            "Evolution", 10, 100.0);
        TextChunk chunk2 = new TextChunk(new BoundingBox(0, 31.5, 100.0, 50.0, 110.0),
            "Of", 10, 100.0);

        contents.add(chunk1);
        contents.add(chunk2);

        List<IObject> result = TextLineProcessor.processTextLines(contents);

        TextLine line = (TextLine) result.get(0);
        String value = line.getValue();
        System.out.println("Test small gap: '" + value + "'");
        // Should have space between words, not concatenated
        if (value.equals("EvolutionOf")) {
            System.out.println("FAIL: Words are concatenated without space! Gap=1.5, threshold=1.7");
            System.exit(1);
        }
        if (!value.contains(" ")) {
            System.out.println("FAIL: No space at all between chunks!");
            System.exit(1);
        }
        System.out.println("PASS: Space correctly inserted for small gap");
    }

    static void testWordGaps() {
        List<IObject> contents = new ArrayList<>();
        // Simulate "Evolution Of Search" - gap between words
        // For fontSize=12, threshold=12*0.17=2.04
        // Gaps: 2.0 between Evolution-Of, 2.0 between Of-Search
        TextChunk chunk1 = new TextChunk(new BoundingBox(0, 10.0, 100.0, 50.0, 112.0),
            "Evolution", 12, 100.0);
        TextChunk chunk2 = new TextChunk(new BoundingBox(0, 52.0, 100.0, 65.0, 112.0),
            "Of", 12, 100.0);
        TextChunk chunk3 = new TextChunk(new BoundingBox(0, 67.0, 100.0, 95.0, 112.0),
            "Search", 12, 100.0);

        contents.add(chunk1);
        contents.add(chunk2);
        contents.add(chunk3);

        List<IObject> result = TextLineProcessor.processTextLines(contents);

        TextLine line = (TextLine) result.get(0);
        String value = line.getValue();
        System.out.println("Test word gaps: '" + value + "'");
        // Should have spaces between words
        if (!value.contains("Evolution") || !value.contains("Of") || !value.contains("Search")) {
            System.out.println("FAIL: Missing words in output: " + value);
            System.exit(1);
        }
        if (value.equals("EvolutionOfSearch")) {
            System.out.println("FAIL: All words concatenated without spaces! Gaps=2.0, threshold=2.04");
            System.exit(1);
        }
        System.out.println("PASS: Spaces correctly inserted between words");
    }

    static void testOverlappingChunks() {
        List<IObject> contents = new ArrayList<>();
        // These chunks overlap - should NOT get a space
        contents.add(new TextChunk(new BoundingBox(0, 10.0, 30.0, 20.0, 40.0),
            "test", 10, 30.0));
        contents.add(new TextChunk(new BoundingBox(0, 20.0, 30.0, 30.0, 40.0),
            "test", 10, 30.0));

        List<IObject> result = TextLineProcessor.processTextLines(contents);
        TextLine line = (TextLine) result.get(0);
        String value = line.getValue();
        System.out.println("Test overlapping: '" + value + "'");
        // Should be "testtest" (no space for overlapping)
        if (!value.equals("testtest")) {
            System.out.println("FAIL: Expected 'testtest' for overlapping chunks, got: " + value);
            System.exit(1);
        }
        System.out.println("PASS: Overlapping chunks correctly not separated");
    }

    static void testLargeGap() {
        List<IObject> contents = new ArrayList<>();
        TextChunk chunk1 = new TextChunk(new BoundingBox(0, 10.0, 300.0, 30.0, 310.0),
            "A:", 10, 300.0);
        TextChunk chunk2 = new TextChunk(new BoundingBox(0, 50.0, 300.0, 150.0, 310.0),
            "answer text", 10, 300.0);

        contents.add(chunk1);
        contents.add(chunk2);

        List<IObject> result = TextLineProcessor.processTextLines(contents);
        TextLine line = (TextLine) result.get(0);
        String value = line.getValue();
        System.out.println("Test large gap: '" + value + "'");
        if (value.equals("A:answer text")) {
            System.out.println("FAIL: Large gap didn't get space!");
            System.exit(1);
        }
        System.out.println("PASS: Large gap correctly has space");
    }
}

